+		}
+	}
+
+	if node := h.Get("key-over-bound"); node == "" {
+		t.Fatal("Get on over-bound path returned empty node")
+	}
+	assertTotalLoadMatchesSum(t, h, nodes)
+
+	if got := h.TotalLoad(); got != 3 {
+		t.Fatalf("TotalLoad() = %d, want 3 after over-bound assignment", got)
+	}
+}
+
+func assertTotalLoadMatchesSum(t *testing.T, h *BoundedLoadHash, nodes []string) {
+	t.Helper()
+
+	sum := 0
+	for _, node := range nodes {
+		sum += h.Load(node)
+	}
+
+	if got := h.TotalLoad(); got != sum {
+		t.Fatalf("TotalLoad() = %d, want sum of node loads %d", got, sum)
+	}
+}
