package consistent

import "testing"

func TestTotalLoadMatchesSumAfterWithinBoundAssignments(t *testing.T) {
	h := NewBoundedLoadHash(5, 100)
	nodes := []string{"node-a", "node-b", "node-c"}
	for _, node := range nodes {
		h.Add(node)
	}

