func TestTotalLoadMatchesSumAfterAssignmentsAndReleases(t *testing.T) {
	h := NewBoundedLoadHash(5, 100)
	nodes := []string{"node-a", "node-b", "node-c"}
	for _, node := range nodes {
		h.Add(node)
	}

	assigned := make([]string, 0, 6)
	for _, key := range []string{"key-0", "key-1", "key-2", "key-3", "key-4", "key-5"} {
		node := h.Get(key)
		if node == "" {
			t.Fatalf("Get(%q) returned empty node", key)
		}
		assigned = append(assigned, node)
	}
	assertTotalLoadMatchesSum(t, h, nodes)

	h.Release(assigned[0])
	assertTotalLoadMatchesSum(t, h, nodes)

	h.Release(assigned[1])
	assertTotalLoadMatchesSum(t, h, nodes)

	if node := h.Get("key-after-release"); node == "" {
		t.Fatal("Get after releases returned empty node")
	}
	assertTotalLoadMatchesSum(t, h, nodes)
