	h := NewBoundedLoadHash(3, 1.0)
	nodes := []string{"node-a", "node-b"}
	for _, node := range nodes {
		h.Add(node)
	}

	for _, key := range []string{"key-0", "key-1"} {
		if node := h.Get(key); node == "" {
			t.Fatalf("Get(%q) returned empty node", key)
		}
		assertTotalLoadMatchesSum(t, h, nodes)
